import { GoogleGenAI, Type } from "@google/genai";
import { ProductionJob, Resource } from "../types";

export const optimizeSchedule = async (jobs: ProductionJob[], resources: Resource[]): Promise<any> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const prompt = `
    Analyze the following production jobs and manufacturing resources. 
    Provide an optimized scheduling sequence that minimizes downtime and prioritizes higher-priority jobs.

    Resources: ${JSON.stringify(resources)}
    Current Jobs: ${JSON.stringify(jobs)}

    Return a plan that includes:
    1. A list of suggested job movements (e.g., reassigning resource or changing start time).
    2. Identification of any potential bottlenecks.
    3. An overall efficiency score of the current plan versus your optimized suggestion.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            suggestions: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  jobId: { type: Type.STRING },
                  recommendation: { type: Type.STRING },
                  impact: { type: Type.STRING }
                }
              }
            },
            bottlenecks: {
              type: Type.ARRAY,
              items: { type: Type.STRING }
            },
            efficiencyScore: { type: Type.NUMBER }
          },
          required: ["suggestions", "bottlenecks", "efficiencyScore"]
        }
      }
    });

    return JSON.parse(response.text);
  } catch (error) {
    console.error("Gemini optimization failed:", error);
    return null;
  }
};

