import React, { useState } from 'react';
import { ProductionJob, Resource } from '../types';
import { COLORS } from '../constants';

interface ScheduleTimelineProps {
  jobs: ProductionJob[];
  resources: Resource[];
}

const ScheduleTimeline: React.FC<ScheduleTimelineProps> = ({ jobs, resources }) => {
  const hours = Array.from({ length: 24 }, (_, i) => i);
  const hourWidth = 120; // px per hour

  const getJobStyle = (job: ProductionJob) => {
    const start = new Date(job.startTime);
    const end = new Date(job.endTime);
    const startHour = start.getHours() + start.getMinutes() / 60;
    const duration = (end.getTime() - start.getTime()) / (1000 * 60 * 60);

    return {
      left: `${startHour * hourWidth}px`,
      width: `${duration * hourWidth}px`,
    };
  };

  return (
    <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden flex flex-col h-[calc(100vh-12rem)]">
      <div className="p-6 border-b border-slate-100 flex items-center justify-between shrink-0">
        <div>
          <h3 className="font-semibold text-slate-800">Production Gantt</h3>
          <p className="text-sm text-slate-500">Live operational timeline for all assembly lines</p>
        </div>
        <div className="flex items-center gap-2">
          <button className="px-3 py-1.5 text-xs font-medium bg-slate-100 text-slate-700 rounded-lg hover:bg-slate-200">Today</button>
          <div className="flex border border-slate-200 rounded-lg overflow-hidden">
            <button className="px-3 py-1.5 text-xs font-medium bg-white hover:bg-slate-50 border-r border-slate-200">Hour</button>
            <button className="px-3 py-1.5 text-xs font-medium bg-slate-50 hover:bg-slate-100">Day</button>
          </div>
        </div>
      </div>

      <div className="flex-1 overflow-auto custom-scrollbar relative">
        {/* Timeline Header */}
        <div className="sticky top-0 z-20 flex bg-slate-50 border-b border-slate-200">
          <div className="w-48 shrink-0 p-3 font-semibold text-xs text-slate-400 border-r border-slate-200 bg-slate-50">Resource</div>
          {hours.map((hour) => (
            <div key={hour} className="shrink-0 text-center py-3 border-r border-slate-100 text-xs font-medium text-slate-500" style={{ width: hourWidth }}>
              {hour}:00
            </div>
          ))}
        </div>

        {/* Resources & Jobs */}
        <div className="relative">
          {resources.map((resource) => (
            <div key={resource.id} className="flex border-b border-slate-100 group">
              <div className="w-48 shrink-0 p-4 border-r border-slate-200 bg-white sticky left-0 z-10 flex flex-col justify-center">
                <span className="font-semibold text-slate-800">{resource.name}</span>
                <span className="text-[10px] uppercase text-slate-400 font-bold">{resource.type}</span>
                <div className="mt-2 flex items-center gap-1.5">
                  <span className={`w-1.5 h-1.5 rounded-full ${resource.status === 'active' ? 'bg-emerald-500' : 'bg-slate-300'}`}></span>
                  <span className="text-[10px] text-slate-500">{resource.capacity}% cap</span>
                </div>
              </div>

              <div className="flex-1 relative h-24 bg-slate-50/30 group-hover:bg-slate-50/50 transition-colors">
                {/* Hourly grid lines */}
                {hours.map((h) => (
                  <div key={h} className="absolute top-0 bottom-0 border-r border-slate-100/50" style={{ left: h * hourWidth }}></div>
                ))}

                {/* Jobs for this resource */}
                {jobs
                  .filter((j) => j.resourceId === resource.id)
                  .map((job) => (
                    <div
                      key={job.id}
                      style={getJobStyle(job)}
                      className={`absolute top-4 bottom-4 rounded-xl border-l-4 shadow-sm p-3 flex flex-col justify-center overflow-hidden cursor-pointer hover:brightness-95 transition-all ${COLORS[job.priority]}`}
                    >
                      <span className="text-xs font-bold truncate leading-tight">{job.title}</span>
                      <div className="flex items-center gap-2 mt-1">
                        <span className="text-[10px] font-medium opacity-80">{job.quantity} units</span>
                        <div className="flex-1 h-1 bg-white/40 rounded-full overflow-hidden">
                          <div className="h-full bg-current rounded-full" style={{ width: `${job.progress}%` }}></div>
                        </div>
                      </div>
                    </div>
                  ))}
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

export default ScheduleTimeline;

import React, { useState } from 'react';
import { Icons } from '../constants';
import { ProductionJob, Resource } from '../types';
import { optimizeSchedule } from '../services/geminiService';

interface SmartOptimizerProps {
  jobs: ProductionJob[];
  resources: Resource[];
}

const SmartOptimizer: React.FC<SmartOptimizerProps> = ({ jobs, resources }) => {
  const [isOptimizing, setIsOptimizing] = useState(false);
  const [result, setResult] = useState<any>(null);

  const handleOptimize = async () => {
    setIsOptimizing(true);
    const data = await optimizeSchedule(jobs, resources);
    setResult(data);
    setIsOptimizing(false);
  };

  return (
    <div className="bg-indigo-900 rounded-3xl p-8 text-white shadow-2xl overflow-hidden relative mb-8">
      <div className="absolute top-0 right-0 p-12 opacity-10 rotate-12">
         <Icons.Sparkles />
      </div>

      <div className="relative z-10 flex flex-col md:flex-row items-center justify-between gap-8">
        <div className="max-w-xl">
          <h2 className="text-3xl font-bold mb-4">AI Schedule Optimization</h2>
          <p className="text-indigo-200 leading-relaxed mb-6">
            Leverage ProSync's advanced reasoning engine to detect bottlenecks, optimize resource allocation, 
            and maximize your daily throughput with just one click.
          </p>
          <button
            onClick={handleOptimize}
            disabled={isOptimizing}
            className={`flex items-center gap-3 px-8 py-4 bg-white text-indigo-900 rounded-2xl font-bold transition-all transform active:scale-95 ${
              isOptimizing ? 'opacity-70 cursor-not-allowed' : 'hover:bg-indigo-50 hover:shadow-lg'
            }`}
          >
            {isOptimizing ? (
              <>
                <div className="w-5 h-5 border-2 border-indigo-900 border-t-transparent rounded-full animate-spin"></div>
                Analyzing Production Data...
              </>
            ) : (
              <>
                <Icons.Sparkles />
                Run Optimization
              </>
            )}
          </button>
        </div>

        {result && (
          <div className="flex-1 w-full bg-white/10 backdrop-blur-md rounded-2xl p-6 border border-white/10">
            <div className="flex items-center justify-between mb-4">
              <span className="text-sm font-semibold uppercase tracking-wider text-indigo-300">Analysis Results</span>
              <span className="bg-emerald-400 text-indigo-950 px-3 py-1 rounded-full text-xs font-bold">
                +{result.efficiencyScore}% Potential
              </span>
            </div>

            <div className="space-y-4">
              <div>
                <p className="text-xs font-bold text-indigo-300 mb-2">CRITICAL BOTTLENECKS</p>
                <div className="flex flex-wrap gap-2">
                  {result.bottlenecks.map((b: string, i: number) => (
                    <span key={i} className="px-3 py-1 bg-rose-500/20 text-rose-200 border border-rose-500/30 rounded-lg text-xs">
                      {b}
                    </span>
                  ))}
                </div>
              </div>

              <div>
                <p className="text-xs font-bold text-indigo-300 mb-2">TOP RECOMMENDATION</p>
                <div className="bg-indigo-800/50 rounded-xl p-4 text-sm text-indigo-100">
                  <p className="font-semibold text-white mb-1">{result.suggestions[0]?.recommendation}</p>
                  <p className="text-xs text-indigo-300">{result.suggestions[0]?.impact}</p>
                </div>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default SmartOptimizer;

